
"use client";

import { useMemo } from "react";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { MinusCircle, NotebookPen, PlusCircle, Trash2, ShoppingCart } from "lucide-react";

export type OrderItem = {
  id: string; // This is now a composite key: menuItemId + options
  menuItemId: string;
  name: string;
  price: number;
  quantity: number;
  vendorName: string;
  username: string;
  options: Record<string, string>;
};

interface OrderSummaryProps {
  order: OrderItem[];
  onUpdateQuantity: (itemId: string, quantity: number) => void;
  onSubmit: () => void;
}

export function OrderSummary({ order, onUpdateQuantity, onSubmit }: OrderSummaryProps) {
  const total = useMemo(() => {
    return order.reduce((sum, item) => sum + item.price * item.quantity, 0);
  }, [order]);

  const vendorName = useMemo(() => {
    return order.length > 0 ? order[0].vendorName : "";
  }, [order]);

  const username = useMemo(() => {
    // Return a default or empty value if order is empty
    return order.length > 0 ? order[0].username : "匿名";
  }, [order]);

  return (
    <Card className="shadow-xl bg-background/80 backdrop-blur-sm transform transition-transform duration-300 lg:-rotate-1 lg:hover:rotate-0">
      <CardHeader className="pb-4">
        <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
                <NotebookPen className="h-7 w-7 text-accent" />
                <CardTitle className="font-headline text-2xl">我的訂單</CardTitle>
            </div>
            {username && <span className="font-body text-sm font-medium text-muted-foreground">訂購人: {username}</span>}
        </div>
        {vendorName && <CardDescription>店家: {vendorName}</CardDescription>}
      </CardHeader>
      <CardContent>
        {order.length === 0 ? (
          <div className="flex flex-col items-center justify-center text-center text-muted-foreground py-10">
            <ShoppingCart className="h-12 w-12 mb-4" />
            <p className="font-body">您的訂單是空的。</p>
            <p className="font-body text-sm">快去挑選想吃的餐點吧！</p>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="max-h-64 overflow-y-auto pr-2 space-y-4">
              {order.map((item) => (
                <div key={item.id} className="flex items-start justify-between font-body text-sm">
                  <div className="flex-1">
                    <p className="font-medium">{item.name}</p>
                    <div className="text-xs text-muted-foreground">
                        {Object.entries(item.options).map(([key, value]) => (
                            <span key={key} className="mr-2">{value}</span>
                        ))}
                    </div>
                    <p className="text-muted-foreground">${item.price}</p>
                  </div>
                  <div className="flex items-center gap-2">
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-7 w-7"
                      onClick={() => onUpdateQuantity(item.id, item.quantity - 1)}
                      aria-label={`減少 ${item.name} 數量`}
                    >
                      <MinusCircle className="h-4 w-4" />
                    </Button>
                    <span className="w-6 text-center font-mono">{item.quantity}</span>
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-7 w-7"
                      onClick={() => onUpdateQuantity(item.id, item.quantity + 1)}
                      aria-label={`增加 ${item.name} 數量`}
                    >
                      <PlusCircle className="h-4 w-4" />
                    </Button>
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-7 w-7 text-destructive/70 hover:text-destructive"
                      onClick={() => onUpdateQuantity(item.id, 0)}
                      aria-label={`移除 ${item.name}`}
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              ))}
            </div>
            <Separator />
            <div className="flex justify-between font-bold text-lg font-headline">
              <span>總計</span>
              <span>${total.toLocaleString()}</span>
            </div>
          </div>
        )}
      </CardContent>
      <CardFooter>
        <Button
          className="w-full bg-accent text-accent-foreground hover:bg-accent/90 text-base py-6"
          disabled={order.length === 0}
          onClick={onSubmit}
        >
          送出訂單
        </Button>
      </CardFooter>
    </Card>
  );
}
