
"use client";

import { useState, useCallback, useMemo } from "react";
import { useSearchParams } from 'next/navigation';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { OrderSummary, type OrderItem } from "@/components/OrderSummary";
import { cn } from "@/lib/utils";
import { useToast } from "@/hooks/use-toast";
import { Badge } from "./ui/badge";
import { Utensils, Settings } from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Label } from "./ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import type { MenuItem, Vendor } from "@/ai/flows/menu-flow";

export type { Vendor, MenuItem };

export type Menu = {
  [key: string]: MenuItem[];
};

interface OrderClientProps {
  vendors: Vendor[];
  menus: Menu;
}

// Helper to generate a unique ID for an order item based on its selections
const generateOrderItemId = (itemId: string, selections: Record<string, string>) => {
  const sortedSelections = Object.keys(selections).sort().map(key => `${key}:${selections[key]}`).join('|');
  return `${itemId}[${sortedSelections}]`;
}

export function OrderClient({ vendors, menus }: OrderClientProps) {
  const [selectedVendor, setSelectedVendor] = useState<Vendor | null>(vendors[0] || null);
  const [order, setOrder] = useState<OrderItem[]>([]);
  const { toast } = useToast();
  const searchParams = useSearchParams();
  const username = searchParams.get('username') || '匿名';

  // State for the options dialog
  const [isOptionDialogOpen, setIsOptionDialogOpen] = useState(false);
  const [currentItem, setCurrentItem] = useState<MenuItem | null>(null);
  const [currentSelections, setCurrentSelections] = useState<Record<string, string>>({});

  const handleSelectVendor = useCallback((vendor: Vendor) => {
    if (order.length > 0 && selectedVendor?.vendorId !== vendor.vendorId) {
       toast({
        variant: "destructive",
        title: "尚有未完成訂單",
        description: "切換店家將會清空目前的訂單，請先完成或取消訂單。",
      });
      return;
    }
    setSelectedVendor(vendor);
  }, [order.length, selectedVendor?.vendorId, toast]);

  const openOptionDialog = (item: MenuItem) => {
      setCurrentItem(item);
      // Set default selections
      const defaultSelections: Record<string, string> = {};
      item.options?.forEach(group => {
          const defaultChoice = group.choices.find(c => c.isDefault) || group.choices[0];
          if (defaultChoice) {
              defaultSelections[group.name] = defaultChoice.name;
          }
      });
      setCurrentSelections(defaultSelections);
      setIsOptionDialogOpen(true);
  };
  
  const handleAddToOrder = (item: MenuItem, vendor: Vendor) => {
    if (item.options && item.options.length > 0) {
      openOptionDialog(item);
    } else {
      // Add directly if no options
      const orderItemId = generateOrderItemId(item.id, {});
      setOrder(prevOrder => {
          const existingItem = prevOrder.find(oi => oi.id === orderItemId);
          if (existingItem) {
              return prevOrder.map(oi => oi.id === orderItemId ? { ...oi, quantity: oi.quantity + 1 } : oi);
          }
          return [...prevOrder, {
              id: orderItemId,
              menuItemId: item.id,
              name: item.name,
              price: item.price,
              quantity: 1,
              vendorName: vendor.vendorName,
              username: decodeURIComponent(username),
              options: {}
          }];
      });
      toast({ title: "已加入訂單", description: `${item.name} 已新增至您的訂單。` });
    }
  };

  const handleConfirmOptions = () => {
    if (!currentItem || !selectedVendor) return;

    let finalPrice = currentItem.price;
    const selectedOptionDetails: Record<string, string> = {};
    
    currentItem.options?.forEach(group => {
        const selectedChoiceName = currentSelections[group.name];
        const choice = group.choices.find(c => c.name === selectedChoiceName);
        if (choice) {
            finalPrice += choice.priceDelta;
            selectedOptionDetails[group.name] = choice.name;
        }
    });

    const orderItemId = generateOrderItemId(currentItem.id, selectedOptionDetails);

    setOrder(prevOrder => {
      const existingItem = prevOrder.find(oi => oi.id === orderItemId);
      if (existingItem) {
        return prevOrder.map(oi => oi.id === orderItemId ? { ...oi, quantity: oi.quantity + 1 } : oi);
      }
      return [...prevOrder, {
        id: orderItemId,
        menuItemId: currentItem.id,
        name: currentItem.name,
        price: finalPrice,
        quantity: 1,
        vendorName: selectedVendor.vendorName,
        username: decodeURIComponent(username),
        options: selectedOptionDetails,
      }];
    });

    toast({ title: "已加入訂單", description: `${currentItem.name} 已新增至您的訂單。` });
    setIsOptionDialogOpen(false);
    setCurrentItem(null);
  };


  const handleUpdateQuantity = useCallback((itemId: string, quantity: number) => {
    setOrder((prevOrder) => {
      if (quantity <= 0) {
        return prevOrder.filter((item) => item.id !== itemId);
      }
      return prevOrder.map((item) =>
        item.id === itemId ? { ...item, quantity } : item
      );
    });
  }, []);

  const handleSubmitOrder = useCallback(() => {
    if (order.length === 0) {
       toast({
        variant: "destructive",
        title: "訂單是空的",
        description: "請先選擇餐點再送出訂單。",
      });
      return;
    }
    // In a real application, this would send the order to the Google Sheets API.
    console.log("訂單已送出:", order);
    toast({
      title: "訂單已送出！",
      description: "感謝您的訂購，請記得付款喔！",
    });
    setOrder([]);
    // Do not reset selected vendor, so user can place another order from the same vendor.
  }, [order, toast]);

  const selectedMenu = useMemo(() => {
    if (!selectedVendor) return [];
    return menus[selectedVendor.vendorId] || [];
  }, [selectedVendor, menus]);

  return (
    <>
    <div className="container mx-auto max-w-screen-xl p-4 sm:p-6 lg:p-8">
      <div className="grid grid-cols-1 lg:grid-cols-3 lg:gap-8">
        <div className="lg:col-span-2 space-y-8">
          {/* Vendor Selection */}
          <section>
            <h2 className="font-headline text-2xl font-bold mb-4">今日店家</h2>
            {vendors.length > 0 ? (
              <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
                {vendors.map((vendor) => (
                  <Card
                    key={vendor.vendorId}
                    onClick={() => handleSelectVendor(vendor)}
                    className={cn(
                      "cursor-pointer transition-all duration-200 hover:shadow-lg hover:-translate-y-1",
                      selectedVendor?.vendorId === vendor.vendorId && "ring-2 ring-primary shadow-lg"
                    )}
                  >
                    <CardHeader>
                      <CardTitle className="font-headline">{vendor.vendorName}</CardTitle>
                      <CardDescription className="font-body">{vendor.description}</CardDescription>
                    </CardHeader>
                  </Card>
                ))}
              </div>
            ) : (
              <Card className="flex flex-col items-center justify-center p-12 text-center text-muted-foreground bg-secondary/30">
                <Utensils className="h-16 w-16 mb-4 text-primary" />
                <h3 className="font-headline text-xl font-bold mb-2">還沒有想到今天要吃什麼...</h3>
                <p className="font-body text-sm">店家正在準備中，請稍後再來看看！</p>
              </Card>
            )}
          </section>

          {/* Menu Display */}
          {selectedVendor && (
            <section>
              <h2 className="font-headline text-2xl font-bold mb-4">{selectedVendor.vendorName} 菜單</h2>
              <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-6">
                {selectedMenu.map((item) => (
                  <Card key={item.id} className="flex flex-col overflow-hidden transition-shadow hover:shadow-xl">
                    <CardHeader>
                      <CardTitle className="font-headline">{item.name}</CardTitle>
                    </CardHeader>
                    <CardContent className="flex-grow">
                      <Badge variant="secondary" className="font-sans text-lg">${item.price}</Badge>
                    </CardContent>
                    <CardFooter>
                      <Button className="w-full" onClick={() => handleAddToOrder(item, selectedVendor)}>
                        {(item.options && item.options.length > 0) ? (
                          <><Settings className="mr-2 h-4 w-4" /> 選擇規格</>
                        ) : "加入訂單"}
                      </Button>
                    </CardFooter>
                  </Card>
                ))}
              </div>
            </section>
          )}
        </div>

        {/* Order Summary */}
        <aside className="pt-8 lg:pt-0">
          <div className="lg:sticky lg:top-24">
            <OrderSummary
              order={order}
              onUpdateQuantity={handleUpdateQuantity}
              onSubmit={handleSubmitOrder}
            />
          </div>
        </aside>
      </div>
    </div>
    
    {/* Options Dialog */}
    <Dialog open={isOptionDialogOpen} onOpenChange={setIsOptionDialogOpen}>
        <DialogContent>
            <DialogHeader>
                <DialogTitle>客製化選項：{currentItem?.name}</DialogTitle>
                <DialogDescription>請選擇您要的規格。</DialogDescription>
            </DialogHeader>
            <div className="space-y-4 py-4">
                {currentItem?.options?.map(group => (
                    <div key={group.name} className="grid grid-cols-4 items-center gap-4">
                        <Label htmlFor={group.name} className="text-right">{group.name}</Label>
                        <Select
                            value={currentSelections[group.name]}
                            onValueChange={(value) => setCurrentSelections(prev => ({ ...prev, [group.name]: value }))}
                        >
                            <SelectTrigger className="col-span-3">
                                <SelectValue placeholder={`選擇${group.name}`} />
                            </SelectTrigger>
                            <SelectContent>
                                {group.choices.map(choice => (
                                    <SelectItem key={choice.name} value={choice.name}>
                                        {choice.name}
                                        {choice.priceDelta > 0 && ` (+$${choice.priceDelta})`}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>
                ))}
            </div>
            <DialogFooter>
                <Button variant="outline" onClick={() => setIsOptionDialogOpen(false)}>取消</Button>
                <Button onClick={handleConfirmOptions}>加入訂單</Button>
            </DialogFooter>
        </DialogContent>
    </Dialog>

    </>
  );
}
